{
  "product_recommendation": {
    "history_ui": "Agregar una sección desplegable simple en /auditar que liste las revalidaciones previas con columnas: fecha, resultado (aprobado/rechazado) y cambio detectado, usando el mismo estilo y espacio actual para no recargar la pantalla.",
    "next_document_logic": "Implementar un algoritmo en backend que, basado en el último estado de IMSS/Infonavit y análisis del expediente, devuelva el documento con mayor impacto para mejorar claridad; mostrar esta recomendación como un banner o tarjeta destacada en /auditar.",
    "clarity_notification": "Mostrar un toast o banner temporal y visible en /auditar cuando se detecte un aumento en claridad tras subir o revalidar información, con mensaje breve y opción para cerrar."
  },
  "technical_recommendation": {
    "backend_contract": "Extender el endpoint actual de /auditar para incluir un array con historial de revalidaciones y un campo con la recomendación del siguiente documento, calculados y almacenados en núcleo; también enviar un flag de cambio de claridad tras cada acción.",
    "frontend_integration": "Reutilizar la pantalla /auditar para renderizar el historial y la recomendación usando datos del mismo endpoint; implementar notificaciones basadas en flag de claridad sin crear rutas nuevas ni modales complejos.",
    "risk_guardrails": "Validar que el historial no exponga datos sensibles fuera del contexto; controlar que la recomendación no sugiera documentos redundantes; asegurar que la notificación no interrumpa flujos críticos ni afecte performance en móviles."
  },
  "priority_order": [
    "history_ui",
    "clarity_notification",
    "next_document_logic"
  ],
  "confidence": "high"
}
